('chef-rule-87', 'reserve_pasta_water', 'Reserve pasta water', 'special', 'pasta', 'risk', '{"isPasta":true}'::jsonb, '{}'::jsonb, 'mandatory', 'high', 'Pasta water is the easiest tool for emulsifying sauce.', NULL, NULL, NULL, 5, 0.85, 'conditional', 3),
('chef-rule-88', 'do_not_rinse_pasta', 'Do not rinse pasta', 'special', 'pasta', 'risk', '{"isPasta":true}'::jsonb, '{}'::jsonb, 'mandatory', 'high', 'Do not rinse pasta unless the dish specifically needs it.', NULL, NULL, NULL, 5, 0.85, 'conditional', 3),
('chef-rule-89', 'preheat_the_grill', 'Preheat the grill', 'special', 'grilling', 'risk', '{"isGrilling":true}'::jsonb, '{}'::jsonb, 'mandatory', 'high', 'A fully preheated grill gives better release and browning.', NULL, NULL, NULL, 5, 0.85, 'conditional', 3),
('chef-rule-90', 'manage_flare_ups', 'Manage flare-ups', 'special', 'grilling', 'risk', '{"isGrilling":true}'::jsonb, '{}'::jsonb, 'recommended', 'medium', 'Control flare-ups by managing excess fat and hot spots.', NULL, NULL, NULL, 3, 0.85, 'conditional', 2),
('chef-rule-91', 'use_carryover_in_baking_too', 'Use carryover in baking too', 'special', 'baking', 'risk', '{"isBaking":true}'::jsonb, '{}'::jsonb, 'recommended', 'medium', 'Carryover heat matters in baking, especially with cookies and bars.', NULL, NULL, NULL, 3, 0.85, 'conditional', 2),
('chef-rule-92', 'let_sauces_settle_briefly', 'Let sauces settle briefly', 'special', 'sauce', 'risk', '{"isSauce":true}'::jsonb, '{}'::jsonb, 'recommended', 'medium', 'A short rest helps sauces thicken and flavors settle.', NULL, NULL, NULL, 3, 0.85, 'conditional', 2),
('chef-rule-93', 'parchment_improves_consistency', 'Parchment improves consistency', 'special', 'baking', 'risk', '{"isBaking":true}'::jsonb, '{}'::jsonb, 'recommended', 'medium', 'Parchment removes a lot of unnecessary baking variance.', NULL, NULL, NULL, 3, 0.85, 'conditional', 2),
('chef-rule-94', 'hydrate_grains_properly', 'Hydrate grains properly', 'special', 'grains', 'risk', '{"isGrains":true}'::jsonb, '{}'::jsonb, 'mandatory', 'high', 'Grains need the right liquid and a proper rest to finish well.', NULL, NULL, NULL, 5, 0.85, 'conditional', 3),
('chef-rule-95', 'rinse_rice_when_appropriate', 'Rinse rice when appropriate', 'special', 'rice', 'risk', '{"isRice":true}'::jsonb, '{}'::jsonb, 'recommended', 'medium', 'Rinsing rice can improve final texture when separate grains matter.', NULL, NULL, NULL, 3, 0.85, 'conditional', 2),
('chef-rule-96', 'toast_rice_for_flavor', 'Toast rice for flavor', 'special', 'rice', 'risk', '{"isRice":true}'::jsonb, '{}'::jsonb, 'recommended', 'medium', 'Toasting rice before adding liquid adds depth.', NULL, NULL, NULL, 3, 0.85, 'conditional', 2),
('chef-rule-97', 'do_not_stir_risotto_nonstop', 'Do not stir risotto nonstop', 'special', 'risotto', 'risk', '{"isRisotto":true}'::jsonb, '{}'::jsonb, 'recommended', 'medium', 'Constant risotto stirring is less important than steady liquid management.', NULL, NULL, NULL, 3, 0.85, 'conditional', 2),
('chef-rule-98', 'finish_some_sauces_with_butter', 'Finish some sauces with butter', 'special', 'finish', 'risk', '{"isSauce":true}'::jsonb, '{}'::jsonb, 'recommended', 'medium', 'A butter finish can round out texture and shine when the dish allows it.', NULL, NULL, NULL, 3, 0.85, 'conditional', 2),
('chef-rule-99', 'acid_revives_flat_dishes', 'Acid revives flat dishes', 'special', 'flavor_fix', 'risk', '{"always":true}'::jsonb, '{}'::jsonb, 'mandatory', 'high', 'When a dish tastes flat, try acid before piling on more salt.', NULL, NULL, NULL, 5, 0.85, 'broad', 3),
('chef-rule-100', 'simplicity_wins', 'Simplicity wins', 'special', 'universal', 'risk', '{"always":true}'::jsonb, '{}'::jsonb, 'mandatory', 'high', 'A simpler, coherent dish usually beats a cluttered one.', NULL, NULL, NULL, 5, 0.85, 'broad', 3),
('chef-rule-101', 'butter_contains_water', 'Butter contains water', 'ingredient', 'fat', 'ingredient', '{"hasButter":true}'::jsonb, '{}'::jsonb, 'recommended', 'medium', 'Butter carries water as well as fat, so it changes browning and texture compared with pure fats.', NULL, NULL, NULL, 3, 0.85, 'conditional', 2),
('chef-rule-102', 'brown_sugar_adds_moisture', 'Brown sugar adds moisture', 'ingredient', 'sugar', 'ingredient', '{"hasBrownSugar":true}'::jsonb, '{}'::jsonb, 'recommended', 'medium', 'Brown sugar holds more moisture and pushes baked goods toward chew and softness.', NULL, NULL, NULL, 3, 0.85, 'conditional', 2),
('chef-rule-103', 'flour_protein_affects_structure', 'Flour protein affects structure', 'ingredient', 'flour', 'ingredient', '{"hasFlour":true}'::jsonb, '{}'::jsonb, 'mandatory', 'high', 'Flour choice changes structure, chew, and tenderness more than most substitutions do.', NULL, NULL, NULL, 5, 0.85, 'conditional', 3),
('chef-rule-104', 'eggs_provide_structure_and_binding', 'Eggs provide structure and binding', 'ingredient', 'egg', 'ingredient', '{"hasEgg":true}'::jsonb, '{}'::jsonb, 'recommended', 'medium', 'Eggs add structure, moisture, and emulsification, so replacing them changes more than richness.', NULL, NULL, NULL, 3, 0.85, 'conditional', 2),
('chef-rule-105', 'frozen_fruit_releases_extra_water', 'Frozen fruit releases extra water', 'ingredient', 'fruit', 'ingredient', '{"hasFrozenFruit":true}'::jsonb, '{}'::jsonb, 'warning', 'high', 'Frozen fruit sheds water into batters and fillings, which can leave baked goods gummy or underbaked.', 'The batter can bake up wet or uneven.', 'add_note', '{"content":"Frozen fruit releases moisture, so avoid overmixing and expect slightly longer bake time."}'::jsonb, 4, 0.85, 'conditional', 4),
('chef-rule-106', 'mushrooms_need_time_to_shed_moisture', 'Mushrooms need time to shed moisture', 'ingredient', 'vegetable', 'ingredient', '{"hasMushrooms":true}'::jsonb, '{}'::jsonb, 'mandatory', 'high', 'Mushrooms release water before they brown, so the pan needs enough time and space to cook that moisture off.', NULL, 'add_note', '{"content":"Cook the mushrooms until they release and then evaporate their moisture before expecting deep browning."}'::jsonb, 5, 0.85, 'conditional', 3),
('chef-rule-107', 'garlic_burns_quickly', 'Garlic burns quickly', 'ingredient', 'aromatic', 'ingredient', '{"hasGarlic":true}'::jsonb, '{}'::jsonb, 'warning', 'high', 'Garlic turns bitter fast on aggressive heat, so add it after the pan has settled down or keep it moving.', 'Burned garlic makes the dish bitter.', 'add_note', '{"content":"Add the garlic after the main browning step or lower the heat so it does not scorch."}'::jsonb, 4, 0.85, 'conditional', 4),
('chef-rule-108', 'cheese_needs_controlled_heat', 'Cheese needs controlled heat', 'ingredient', 'dairy', 'ingredient', '{"hasCheese":true}'::jsonb, '{}'::jsonb, 'warning', 'high', 'Cheese can split or turn greasy when the heat stays too high, especially in sauces.', 'The sauce can break or turn grainy.', 'add_note', '{"content":"Lower the heat before adding cheese so it melts smoothly instead of separating."}'::jsonb, 4, 0.85, 'conditional', 4),
('chef-rule-109', 'garlic_is_high_risk_on_high_heat', 'Garlic is high-risk on high heat', 'special', 'aromatic_risk', 'risk', '{"hasGarlic":true,"usesHighHeat":true}'::jsonb, '{}'::jsonb, 'warning', 'high', 'High heat plus garlic is a common bitterness trap unless timing is controlled carefully.', NULL, 'add_note', '{"content":"If the pan is very hot, add the garlic later or pull the heat back before it goes in."}'::jsonb, 4, 0.85, 'conditional', 4),
('chef-rule-110', 'sauces_need_a_final_seasoning_check', 'Sauces need a final seasoning check', 'special', 'sauce_seasoning', 'risk', '{"isSauce":true}'::jsonb, '{}'::jsonb, 'recommended', 'medium', 'Sauces almost always need a final taste after reduction because salt and acid shift as they cook.', NULL, 'add_note', '{"content":"Taste the sauce at the end and adjust salt or acid before serving."}'::jsonb, 3, 0.85, 'conditional', 2)
